import { useCallback } from 'react';

async function callAI(prompt, maxTokens = 1500) {
  const r = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json',
      'x-api-key': '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',
      'anthropic-version': '2023-06-01',
      'anthropic-dangerous-direct-browser-access': 'true' },
    body: JSON.stringify({
      model: 'claude-sonnet-4-20250514',
      max_tokens: maxTokens,
      messages: [{ role: 'user', content: prompt }],
    }),
  });
  const d = await r.json();
  return d.content?.map(c => c.text || '').join('');
}

function parseJSON(raw) {
  return JSON.parse(raw.replace(/```json|```/g, '').trim());
}

export function useAI() {
  const getAIPicks = useCallback(async (priceCtx) => {
    const today = new Date().toDateString();
    const prompt = `Today is ${today}. Stock prices and daily changes:\n${priceCtx}\n\nYou are a quantitative day-trading analyst. Identify exactly:\n1. The TOP 5 stocks to BUY today (best upside momentum, trend, catalyst)\n2. The TOP 5 stocks to SHORT/SELL today (clearest bearish signals)\n\nLimit each list to exactly 5. Reply ONLY with this exact JSON (no markdown fences):\n{"buys":[{"sym":"AAPL","reason":"2 sentences max","exit":"specific exit condition","confidence":"High|Medium|Low"}],"shorts":[{"sym":"TSLA","reason":"2 sentences max","cover":"specific cover condition","confidence":"High|Medium|Low"}]}`;
    const raw = await callAI(prompt);
    return parseJSON(raw);
  }, []);

  const getCloseSignals = useCallback(async (posCtx) => {
    const raw = await callAI(
      `A trader holds these long positions:\n${posCtx}\n\nFor EACH position, assess if today's price action suggests closing. Reply ONLY with JSON array:\n[{"sym":"AAPL","action":"CLOSE|HOLD","reason":"1 sentence","urgency":"Urgent|Monitor|Hold"}]`,
      800
    );
    return parseJSON(raw);
  }, []);

  const getCoverSignals = useCallback(async (posCtx) => {
    const raw = await callAI(
      `A trader has these short positions:\n${posCtx}\n\nFor EACH, assess if today's action suggests covering. Reply ONLY with JSON:\n[{"sym":"TSLA","action":"COVER|HOLD","reason":"1 sentence","urgency":"Urgent|Monitor|Hold"}]`,
      800
    );
    return parseJSON(raw);
  }, []);

  const getCryptoRecs = useCallback(async (priceCtx) => {
    const today = new Date().toDateString();
    const prompt = `Today is ${today}. Crypto prices:\n${priceCtx}\n\nYou are a crypto day-trading analyst. For each of these 10 cryptocurrencies provide a day-trading recommendation.\n\nReply ONLY with JSON array (no markdown):\n[{"ticker":"BTC","rec":"BUY|SELL|HOLD","reason":"2 sentences","oi_tier":"Very High|High|Medium|Low|Very Low","oi_note":"brief context","confidence":"High|Medium|Low"}]`;
    const raw = await callAI(prompt);
    return parseJSON(raw);
  }, []);

  return { getAIPicks, getCloseSignals, getCoverSignals, getCryptoRecs };
}
